import { Checkbox } from "antd"
import SvgIcon from "src/components/SvgIcon"

const FinalConfirmation = ({ onChange, checkedValues, confirmError }) => {
  const checkboxItems = [
    {
      id: 0,
      label:
        "Tôi xác nhận rằng mọi thông tin được cung cấp ở trên là chính xác và đầy đủ theo hiểu biết của tôi.",
      errorMessage: "Vui lòng xác nhận thông tin này.",
    },
    {
      id: 1,
      label:
        "Tôi đã đọc và đồng ý với Điều khoản và Điều kiện và Chính sách Bảo mật.",
      errorMessage: "Vui lòng đồng ý với điều khoản và chính sách.",
    },
  ]

  const handleCheckboxChange = index => e => {
    onChange(index, e.target.checked)
  }

  const renderCheckbox = item => {
    const isChecked = checkedValues[item.id]
    const hasError = confirmError && !isChecked

    return (
      <div key={item.id} style={{ marginBottom: item.id === 0 ? 16 : 0 }}>
        <Checkbox checked={isChecked} onChange={handleCheckboxChange(item.id)}>
          <b className="fs-12">{item.label}</b>
        </Checkbox>
        {hasError && (
          <div style={{ color: "red", fontSize: 12, marginTop: 4 }}>
            {item.errorMessage}
          </div>
        )}
      </div>
    )
  }

  return (
    <div className="business-register__step-coinfirm1">
      <div className="coinfirm-content">
        <div
          className="d-flex-start"
          style={{
            alignItems: "flex-end",
            gap: "10px",
          }}
        >
          <div className="pb-8">
            <SvgIcon name="t_warning_default" />
          </div>
          <div>
            <div className="fw-600">Xác nhận cuối cùng</div>
          </div>
        </div>

        <div className="fs-14">{checkboxItems.map(renderCheckbox)}</div>
      </div>
    </div>
  )
}

export default FinalConfirmation
