import { Col, Divider, Row, Typography } from "antd"
import { useEffect, useState } from "react"
import ButtonCustom from "src/components/MyButton/Button"
import FinalConfirmation from "./FinalConfirmation"
import InformationApplication from "./InformationApplication"

const { Paragraph } = Typography

const Step4 = ({
  success,
  prev,
  formValues,
  treeExternalData,
  setCurrent,
  loading,
}) => {
  const [avatarPreview, setAvatarPreview] = useState("")
  const [confirmChecks, setConfirmChecks] = useState([false, false])
  const [confirmError, setConfirmError] = useState(false)
  const [isMobile, setIsMobile] = useState(false)
  const [isTablet, setIsTablet] = useState(false)
  console.log("formValues", formValues)
  console.log("treeExternalData", treeExternalData)

  useEffect(() => {
    const checkScreenSize = () => {
      const width = window.innerWidth
      setIsMobile(width < 768)
      setIsTablet(width >= 768 && width < 1024)
    }

    checkScreenSize()
    window.addEventListener("resize", checkScreenSize)
    return () => {
      window.removeEventListener("resize", checkScreenSize)
    }
  }, [])

  useEffect(() => {
    if (formValues?.CCCDImage?.[0]?.originFileObj) {
      const fileObj = formValues.CCCDImage[0].originFileObj
      const url = URL.createObjectURL(fileObj)
      setAvatarPreview(url)
    }
  }, [formValues?.CCCDImage])

  useEffect(() => {
    return () => {
      if (avatarPreview?.startsWith("blob:")) {
        URL.revokeObjectURL(avatarPreview)
      }
    }
  }, [avatarPreview])

  const handleCheckboxChange = (index, checked) => {
    const newChecks = [...confirmChecks]
    newChecks[index] = checked
    setConfirmChecks(newChecks)

    if (newChecks.every(Boolean)) {
      setConfirmError(false)
    }
  }

  const handleSubmit = () => {
    const allChecked = confirmChecks.every(Boolean)
    if (!allChecked) {
      setConfirmError(true)
      return
    }
    setConfirmError(false)
    success()
  }

  const getImageHeight = () => {
    if (isMobile) return 60
    if (isTablet) return 80
    return 100
  }

  const EditButton = ({ stepIndex }) => (
    <ButtonCustom
      iconName="edit-semina"
      variant="text"
      onClick={() => setCurrent(stepIndex)}
      size={isMobile ? "small" : "default"}
    >
      {isMobile ? "Sửa" : "Edit"}
    </ButtonCustom>
  )

  const InfoField = ({
    label,
    value,
    copyable = false,
    colSpan = { xs: 24, sm: 12, md: 12, lg: 12 },
  }) => (
    <Col {...colSpan}>
      <div className="field-infor">
        <div className="field-name">{label}</div>
        <div className="field-content">
          {copyable && value ? (
            <Paragraph
              copyable
              style={{ margin: 0, fontSize: "inherit", fontWeight: "inherit" }}
            >
              {value}
            </Paragraph>
          ) : (
            value || <i>Chưa có thông tin</i>
          )}
        </div>
      </div>
    </Col>
  )

  return (
    <div className="business-register__step">
      <div className="step4-content-wrapper">
        <div className="step4-info-section">
          {/* Step 1: Business Information */}
          <Row gutter={[16, 24]}>
            <Col xs={24} lg={12}>
              <div className="box-infor-b1">
                <div className="d-flex-sb">
                  <h4 className="fw-600">
                    {isMobile
                      ? "Bước 1: Thông tin DN"
                      : "Bước 1: Thông tin doanh nghiệp"}
                  </h4>
                  <EditButton stepIndex={0} />
                </div>

                <Divider style={{ borderColor: "#01b39e", margin: "8px 0" }} />

                <Row gutter={[8, 8]}>
                  <InfoField
                    label="Mã số thuế"
                    value={formValues?.TaxCode}
                    colSpan={{ xs: 24, sm: 12, md: 12, lg: 12 }}
                  />
                  <InfoField
                    label="Tên Doanh Nghiệp"
                    value={formValues?.OrganizationName}
                    colSpan={{ xs: 24, sm: 12, md: 12, lg: 12 }}
                  />
                  <InfoField
                    label="Địa chỉ"
                    value={formValues?.Address}
                    colSpan={{ xs: 24, sm: 24, md: 24, lg: 24 }}
                  />
                  <InfoField
                    label="Ngày cấp"
                    value={formValues?.DateIssue?.format?.("DD/MM/YYYY")}
                    colSpan={{ xs: 24, sm: 12, md: 12, lg: 12 }}
                  />

                  <Col xs={24} md={12}>
                    <div className="field-infor">
                      <div className="field-name">
                        Giấy đăng ký doanh nghiệp
                      </div>
                      <div className="field-content">
                        {avatarPreview ? (
                          <img
                            src={avatarPreview}
                            alt="Giấy đăng ký doanh nghiệp"
                            style={{
                              height: getImageHeight(),
                              width: "auto",
                              objectFit: "contain",
                              maxWidth: "100%",
                              borderRadius: "4px",
                              border: "1px solid #d9d9d9",
                            }}
                          />
                        ) : (
                          <i>Chưa có ảnh</i>
                        )}
                      </div>
                    </div>
                  </Col>
                </Row>

                <Divider>
                  <b style={{ fontSize: isMobile ? "12px" : "14px" }}>
                    Thông tin liên lạc
                  </b>
                </Divider>

                <Row gutter={[8, 8]}>
                  <InfoField
                    label="Số điện thoại"
                    value={formValues?.PhoneNumber}
                    copyable={true}
                    colSpan={{ xs: 24, sm: 12, md: 12, lg: 10 }}
                  />
                  <InfoField
                    label="Email"
                    value={formValues?.Email}
                    copyable={true}
                    colSpan={{ xs: 24, sm: 12, md: 12, lg: 14 }}
                  />
                  <InfoField
                    label="Mô tả"
                    value={formValues?.Description}
                    colSpan={{ xs: 24, sm: 24, md: 24, lg: 24 }}
                  />
                </Row>
              </div>
            </Col>

            {/* Step 2 & 3: Unit and Representative Information */}
            <Col xs={24} lg={12}>
              {/* Step 2: Unit Information */}
              <div className="box-infor-b2">
                <div className="d-flex-sb">
                  <h4 className="fw-600">Bước 2: Thông tin đơn vị</h4>
                  <EditButton stepIndex={1} />
                </div>

                <Divider style={{ borderColor: "#01b39e", margin: "8px 0" }} />

                <Row gutter={[8, 8]}>
                  <InfoField
                    label="Đơn vị"
                    value={treeExternalData?.selectedUnit?.AccountName}
                    colSpan={{ xs: 24, sm: 24, md: 24, lg: 24 }}
                  />
                </Row>
              </div>

              {/* Step 3: Representative Information */}
              <div className="box-infor-b3">
                <div className="d-flex-sb">
                  <h4 className="fw-600">
                    {isMobile
                      ? "Bước 3: Người đại diện"
                      : "Bước 3: Thông tin người đại diện"}
                  </h4>
                  <EditButton stepIndex={2} />
                </div>

                <Divider style={{ borderColor: "#01b39e", margin: "8px 0" }} />

                <Row gutter={[8, 8]}>
                  <InfoField
                    label="Họ và tên"
                    value={formValues?.RepresentativeName}
                    colSpan={{ xs: 24, sm: 12, md: 12, lg: 12 }}
                  />
                  <InfoField
                    label="Số điện thoại"
                    value={formValues?.RepresentativePhoneNumber}
                    copyable={true}
                    colSpan={{ xs: 24, sm: 12, md: 12, lg: 12 }}
                  />
                  <InfoField
                    label="Email"
                    value={formValues?.RepresentativeEmail}
                    copyable={true}
                    colSpan={{ xs: 24, sm: 24, md: 24, lg: 24 }}
                  />
                  <InfoField
                    label="Chức vụ"
                    value={formValues?.RepresentativePosition}
                    colSpan={{ xs: 24, sm: 24, md: 24, lg: 24 }}
                  />
                  <InfoField
                    label="Địa chỉ liên lạc"
                    value={formValues?.RepresentativeAddress}
                    colSpan={{ xs: 24, sm: 24, md: 24, lg: 24 }}
                  />
                </Row>
              </div>
            </Col>
          </Row>
        </div>

        {/* Information Application Section */}
        <Row>
          <Col span={24}>
            <InformationApplication />
          </Col>
        </Row>

        {/* Final Confirmation Section */}
        <Row>
          <Col span={24}>
            <FinalConfirmation
              checkedValues={confirmChecks}
              onChange={handleCheckboxChange}
              confirmError={confirmError}
            />
          </Col>
        </Row>
      </div>

      {/* Action Buttons */}
      <div className={"d-flex-end mt-16"}>
        <ButtonCustom
          disabled={loading}
          onClick={prev}
          style={{
            margin: "0 8px",
            backgroundColor: "#fff",
            color: "#01b39e",
            border: "1px solid #01b39e",
          }}
        >
          Quay lại
        </ButtonCustom>

        <ButtonCustom
          loading={loading}
          disabled={loading}
          type="primary"
          onClick={handleSubmit}
          style={{}}
        >
          {loading ? "Đang xử lý..." : "Tiếp tục"}
        </ButtonCustom>
      </div>
    </div>
  )
}

export default Step4
