import { SearchOutlined } from "@ant-design/icons"
import { Button, Col, Form, Row, Upload } from "antd"
import dayjs from "dayjs"
import { useEffect, useState } from "react"
import DatePickerCustom from "src/components/Date/DatePickerCustom"
import InputCustom from "src/components/Input/InputCustom"
import ButtonCustom from "src/components/MyButton/Button"
import notice from "src/components/Notice"
import SvgIcon from "src/components/SvgIcon"
import { ButtonUploadStyle } from "src/components/Upload/styled"
import { getRegexMobile } from "src/lib/stringsUtils"
import { normFile, validatorFileExtension } from "src/lib/utils"
import AuthService from "src/services/AuthService"
import { validateDate } from "../../IndividualRegistration/utils/cccdUtils"

const Step1 = ({ form, next }) => {
  const acceptFile = ".png, .jpg, .jpeg, .PNG, .JPG, .JPEG"
  const [loading, setLoading] = useState()
  const [isMobile, setIsMobile] = useState(false)
  const [isTablet, setIsTablet] = useState(false)

  useEffect(() => {
    const checkDevice = () => {
      const width = window.innerWidth
      if (width < 768) {
        setIsMobile(true)
        setIsTablet(false)
      } else if (width >= 768 && width < 1024) {
        setIsMobile(false)
        setIsTablet(true)
      } else {
        setIsMobile(false)
        setIsTablet(false)
      }
    }

    checkDevice()
    window.addEventListener("resize", checkDevice)
    return () => {
      window.removeEventListener("resize", checkDevice)
    }
  }, [])

  const searchInfoByCode = async code => {
    if (!code) return
    try {
      setLoading(true)
      const res1 = await AuthService.getInfoByTaxCode(code)
      if (res1.data.code === "00") {
        form.setFieldsValue({
          OrganizationName: res1.data?.data?.name,
          Address: res1.data?.data?.address,
        })
      } else {
        notice({
          isSuccess: false,
          msg: res1.data.desc,
        })
      }
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="business-register__step">
      <Form form={form} layout="vertical" className="pt-5">
        <Row gutter={[16, 16]}>
          <Col xs={24} sm={24} md={24} lg={12} xl={12}>
            <h3
              style={{
                width: isMobile ? "100%" : "75%",
                borderBottom: "2px #01b39e solid",
                color: "#000000",
                fontWeight: 600,
                fontSize: isMobile ? 15 : 17,
                fontFamily: "Inter",
                marginBottom: 16,
                paddingBottom: 8,
                textAlign: isMobile ? "center" : "left",
              }}
            >
              Thông tin doanh nghiệp
            </h3>
            <div className="box-infor">
              <Row gutter={[16, 16]}>
                {/* Cột Trái */}
                <Col xs={24} md={14}>
                  <Form.Item
                    name="TaxCode"
                    label="Tra cứu mã số thuế"
                    rules={[
                      { required: true, message: "Vui lòng nhập mã số thuế" },
                      {
                        pattern: /^(\d{10}|\d{10}-\d{3})$/,
                        message: "Mã số thuế không hợp lệ",
                      },
                    ]}
                  >
                    <InputCustom
                      placeholder="Nhập mã số thuế"
                      type="search"
                      loading={loading}
                      onSearch={searchInfoByCode}
                      enterButton={
                        <div className="d-flex-center">
                          <SearchOutlined
                            style={{ color: "#ffffff", cursor: "pointer" }}
                          />
                        </div>
                      }
                    />
                  </Form.Item>

                  <Form.Item
                    name="OrganizationName"
                    label="Tên doanh nghiệp"
                    rules={[
                      {
                        required: true,
                        message: "Vui lòng nhập tên doanh nghiệp",
                      },
                    ]}
                  >
                    <InputCustom placeholder="Nhập tên doanh nghiệp" />
                  </Form.Item>

                  <Form.Item
                    name="Address"
                    label="Địa chỉ"
                    rules={[
                      {
                        required: true,
                        message: "Vui lòng nhập địa chỉ chi tiết",
                      },
                    ]}
                  >
                    <InputCustom placeholder="Nhập địa chỉ" />
                  </Form.Item>
                </Col>

                {/* Cột Phải */}
                <Col xs={24} md={10}>
                  <Form.Item
                    name="CCCDImage"
                    valuePropName="fileList"
                    getValueFromEvent={normFile}
                    label={
                      <span style={{ fontWeight: 600 }}>
                        Giấy đăng ký kinh doanh
                      </span>
                    }
                    rules={[
                      {
                        required: true,
                        message: "Thông tin không được để trống!",
                      },
                      () => ({
                        validator(_, value) {
                          if (
                            value?.find(
                              i => !validatorFileExtension(i?.name, acceptFile),
                            )
                          ) {
                            return Promise.reject(
                              new Error(`Chỉ được tải file ${acceptFile}`),
                            )
                          }
                          return Promise.resolve()
                        },
                      }),
                    ]}
                  >
                    <Upload
                      accept={acceptFile}
                      multiple={false}
                      beforeUpload={() => false}
                      listType="picture-card"
                      style={{
                        background: "#fff",
                        border: "none",
                        width: "100%",
                      }}
                    >
                      <ButtonUploadStyle>
                        <Button
                          className="account-button-upload"
                          style={{
                            width: "100%",
                            height: "auto",
                            minHeight: "32px",
                          }}
                        >
                          <Row className="account-background-upload d-flex align-items-center justify-content-center">
                            <SvgIcon name="add-media-video" />
                            <div className="account-text-upload ml-8">
                              Chọn ảnh
                            </div>
                          </Row>
                        </Button>
                      </ButtonUploadStyle>
                    </Upload>
                  </Form.Item>

                  <Form.Item
                    name="DateIssue"
                    label="Ngày cấp"
                    rules={[{ validator: validateDate }]}
                  >
                    <DatePickerCustom
                      placeholder="Chọn"
                      format="DD/MM/YYYY"
                      style={{ width: "100%" }}
                      disabledDate={current => {
                        return current && current.isAfter(dayjs().endOf("day"))
                      }}
                    />
                  </Form.Item>
                </Col>
              </Row>
            </div>
          </Col>

          {/* Box thông tin liên lạc */}
          <Col
            xs={24}
            sm={24}
            md={24}
            lg={12}
            xl={12}
            style={{ marginTop: isMobile || isTablet ? 5 : 0 }}
          >
            <h3
              style={{
                width: isMobile ? "100%" : "75%",
                borderBottom: "2px #01b39e solid",
                color: "#000000",
                fontWeight: 600,
                fontSize: isMobile ? 15 : 17,
                fontFamily: "Inter",
                marginBottom: 16,
                paddingBottom: 8,
                textAlign: isMobile ? "center" : "left",
              }}
            >
              Thông Tin Liên lạc
            </h3>
            <div className="box-infor">
              <Row gutter={[16, 16]}>
                {/* Phone Number */}
                <Col xs={24} sm={12} md={12} lg={12} xl={12}>
                  <Form.Item
                    name="PhoneNumber"
                    label="Số Điện Thoại"
                    rules={[
                      {
                        required: true,
                        message: "Vui lòng nhập số điện thoại",
                      },
                      {
                        pattern: getRegexMobile(),
                        message:
                          "Số điện thoại là chuỗi từ 10 đến 11 kí tự chữ số",
                      },
                    ]}
                  >
                    <InputCustom placeholder="Nhập số điện thoại" />
                  </Form.Item>
                </Col>

                {/* Email */}
                <Col xs={24} sm={12} md={12} lg={12} xl={12}>
                  <Form.Item
                    name="Email"
                    label="Email"
                    rules={[
                      { required: true, message: "Vui lòng nhập email" },
                      { type: "email", message: "Email không hợp lệ" },
                    ]}
                  >
                    <InputCustom placeholder="Nhập email" />
                  </Form.Item>
                </Col>

                {/* Description */}
                <Col span={24}>
                  <Form.Item name="Description" label="Mô Tả">
                    <InputCustom
                      type={"textarea"}
                      className="custom-textarea"
                      placeholder="Nhập mô tả ..."
                      rows={isMobile ? 4 : 6}
                    />
                  </Form.Item>
                </Col>
              </Row>
            </div>
          </Col>
        </Row>

        {/* Continue Button */}
        <div
          style={{
            marginTop: 20,
            textAlign: "right",
            // paddingBottom: 16,
          }}
        >
          <ButtonCustom
            type="primary"
            loading={loading}
            onClick={async () => {
              try {
                const values = await form.validateFields()
                next(values)
              } catch (error) {
                console.log("Validation failed:", error)
              }
            }}
          >
            Tiếp tục
          </ButtonCustom>
        </div>
      </Form>
    </div>
  )
}

export default Step1
