import { Col, Form, Row } from "antd"
import { useEffect, useState } from "react"
import InputCustom from "src/components/Input/InputCustom"
import ButtonCustom from "src/components/MyButton/Button"
import { getRegexMobile } from "src/lib/stringsUtils"

const Step3 = ({ form, prev, next }) => {
  const [isMobile, setIsMobile] = useState(false)

  useEffect(() => {
    const checkIsMobile = () => {
      setIsMobile(window.innerWidth < 768)
    }
    checkIsMobile()
    window.addEventListener("resize", checkIsMobile)
    return () => {
      window.removeEventListener("resize", checkIsMobile)
    }
  }, [])

  const getColSpan = desktopSpan => ({
    xs: 24,
    sm: 24,
    md: desktopSpan,
    lg: desktopSpan,
    xl: desktopSpan,
  })

  const getFormItemColSpan = desktopSpan => ({
    xs: 24,
    sm: isMobile ? 24 : desktopSpan,
    md: desktopSpan,
    lg: desktopSpan,
    xl: desktopSpan,
  })

  return (
    <div className="business-register__step">
      <Form form={form} layout="vertical" className="registration-form">
        {/* <NoticeStep
          icon="user-green"
          title="Thông Tin Đại Diện Pháp Lý"
          description="Vui lòng cung cấp thông tin về người được ủy quyền sẽ đại diện cho công ty trong các vấn đề pháp lý."
        /> */}

        <Row gutter={[16, 16]}>
          <Col {...getColSpan(24)}>
            <h3
              style={{
                width: isMobile ? "100%" : "75%",
                borderBottom: "2px #01b39e solid",
                color: "#000000",
                fontWeight: 600,
                fontSize: isMobile ? 15 : 17,
                fontFamily: "Inter",
                textAlign: isMobile ? "center" : "left",
              }}
            >
              Thông Tin Người Đại Diện
            </h3>
            <div>
              <Row gutter={[16, 16]}>
                {/* <Col span={24}></Col> */}

                <Col {...getFormItemColSpan(6)}>
                  <Form.Item
                    name="RepresentativeName"
                    label="Họ và tên"
                    rules={[
                      {
                        required: true,
                        message: "Vui lòng nhập tên người đại diện",
                      },
                    ]}
                  >
                    <InputCustom placeholder="Nhập họ và tên" />
                  </Form.Item>
                </Col>

                <Col {...getFormItemColSpan(12)}>
                  <Form.Item
                    name="RepresentativeEmail"
                    label="Email"
                    rules={[
                      { required: true, message: "Vui lòng nhập email" },
                      { type: "email", message: "Email không hợp lệ" },
                    ]}
                  >
                    <InputCustom placeholder="Nhập email" />
                  </Form.Item>
                </Col>

                <Col {...getFormItemColSpan(6)}>
                  <Form.Item
                    name="RepresentativePhoneNumber"
                    label="Số điện thoại"
                    rules={[
                      {
                        required: true,
                        message: "Vui lòng nhập số điện thoại",
                      },
                      {
                        pattern: getRegexMobile(),
                        message:
                          "Số điện thoại là chuỗi từ 10 đến 11 kí tự chữ số",
                      },
                    ]}
                  >
                    <InputCustom placeholder="Nhập số điện thoại" />
                  </Form.Item>
                </Col>

                <Col {...getFormItemColSpan(12)}>
                  <Form.Item name="RepresentativePosition" label="Chức vụ">
                    <InputCustom placeholder="Nhập chức vụ" />
                  </Form.Item>
                </Col>

                <Col {...getFormItemColSpan(12)}>
                  <Form.Item
                    name="RepresentativeAddress"
                    label="Địa chỉ"
                    rules={[
                      {
                        required: true,
                        message: "Vui lòng nhập địa chỉ chi tiết",
                      },
                    ]}
                  >
                    <InputCustom placeholder="Nhập địa chỉ chi tiết" />
                  </Form.Item>
                </Col>
              </Row>
            </div>
          </Col>
        </Row>
        <br />
        <div className={"d-flex-end"}>
          <ButtonCustom
            style={{
              margin: "0 8px",
              backgroundColor: "#fff",
              color: "#01b39e",
              border: "1px solid #01b39e",
            }}
            onClick={() => prev()}
          >
            Quay lại
          </ButtonCustom>
          <ButtonCustom
            type="primary"
            onClick={async () => {
              const values = await form.validateFields()
              next(values)
            }}
          >
            Tiếp tục
          </ButtonCustom>
        </div>
      </Form>
    </div>
  )
}

export default Step3
