import { Col, Form, Input, message, Row } from "antd"
import ButtonCustom from "src/components/MyButton/Button"
import UnitSelect from "./UnitSelect"

const Step2 = ({ form, prev, next, treeExternalData, setTreeExternalData }) => {
  const handleUnitChange = node => {
    setTreeExternalData(prev => ({
      ...prev,
      selectedUnit: {
        AccountID: node?.key || null,
        AccountName: node?.title || "",
      },
    }))

    // Gán vào Form cha
    form.setFieldsValue({
      AccountID: node?.key || null,
      AccountName: node?.title || "",
    })
  }

  const handleNext = async () => {
    try {
      const values = await form.validateFields(["AccountID"])
      if (!values.AccountID) {
        message.error("Vui lòng chọn đơn vị trước khi tiếp tục")
        return
      }
      next()
    } catch (err) {
      message.error("Vui lòng chọn đơn vị trước khi tiếp tục")
    }
  }

  return (
    <div className="business-register__step">
      <div
        style={{
          width: window.matchMedia("(max-width: 768px)").matches
            ? "100%"
            : "1260px",
          margin: "0 auto",
        }}
      >
        <Form form={form} layout="vertical" preserve={true}>
          <Form.Item
            name="AccountID"
            hidden
            rules={[{ required: true, message: "Vui lòng chọn đơn vị" }]}
          >
            <Input />
          </Form.Item>

          <Form.Item name="AccountName" hidden>
            <Input />
          </Form.Item>

          <Row justify="center">
            <Col xs={24}>
              <div
                style={{
                  minHeight: "500px",
                  display: "flex",
                  flexDirection: "column",
                }}
              >
                <UnitSelect onChange={handleUnitChange} />
              </div>
            </Col>
          </Row>

          <div
            className="d-flex-end"
            style={{
              marginTop: 24,
              display: "flex",
              justifyContent: "flex-end",
              alignItems: "center",
            }}
          >
            <ButtonCustom
              type="default"
              onClick={prev}
              style={{
                margin: "0 8px",
                backgroundColor: "#fff",
                color: "#01b39e",
                border: "1px solid #01b39e",
              }}
            >
              Quay lại
            </ButtonCustom>
            <ButtonCustom type="primary" onClick={handleNext}>
              Tiếp tục
            </ButtonCustom>
          </div>
        </Form>
      </div>
    </div>
  )
}

export default Step2
