import { HomeOutlined, SearchOutlined, TeamOutlined } from "@ant-design/icons"
import { Empty, Input, Spin, Tree } from "antd"
import _ from "lodash"
import { useEffect, useState } from "react"
import { GUIDE_EMPTY } from "src/constants/constants"
import { removeDiacritics } from "src/lib/stringsUtils"
import GuestService from "src/services/GuestService"

const { Search } = Input

export const sort = items =>
  _.orderBy(items, ["Level", "SortOrder"], ["asc", "asc"])

export const nest = (items, id, link) =>
  items
    ?.filter(item => item[link] === id)
    .map(item => ({
      ...item,
      title: item.title,
      key: item?.key,
      children: nest(items, item?.key, link),
    }))

const UnitSelect = ({ onChange }) => {
  const [treeData, setTreeData] = useState([])
  const [filteredTreeData, setFilteredTreeData] = useState([])
  const [loading, setLoading] = useState(false)
  const [searchValue, setSearchValue] = useState("")
  const [expandedKeys, setExpandedKeys] = useState([])
  const [selectedKeys, setSelectedKeys] = useState([])
  const [selectedNode, setSelectedNode] = useState(null)

  const getListUnit = async () => {
    try {
      setLoading(true)
      const res = await GuestService.getAccount({
        PageSize: 1000,
        CurrentPage: 1,
        TextSearch: "",
      })
      if (res?.isError) return
      const data = res?.Object?.lstAccountVM
      const dataList = data?.map(item => ({
        ...item,
        key: item?.AccountID,
        title: item?.AccountName || "",
        removeDiacriticsTitle: removeDiacritics(
          item?.AccountName.toLowerCase(),
        ),
      }))

      const tree = nest(sort(dataList), GUIDE_EMPTY, "ParentID")
      setTreeData(tree)
      setFilteredTreeData(tree)

      // Auto expand all
      const getAllKeys = data => {
        let keys = []
        data.forEach(item => {
          keys.push(item.key)
          if (item.children) keys = keys.concat(getAllKeys(item.children))
        })
        return keys
      }
      setExpandedKeys(getAllKeys(tree))
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    getListUnit()
  }, [])

  const filterTreeData = (data, searchText) => {
    if (!searchText) return data
    const filtered = []

    const filterNode = node => {
      const titleMatch = removeDiacritics(node.title.toLowerCase()).includes(
        removeDiacritics(searchText.toLowerCase()),
      )
      let filteredChildren = []
      if (node.children) {
        filteredChildren = node.children
          .map(child => filterNode(child))
          .filter(child => child !== null)
      }
      if (titleMatch || filteredChildren.length > 0) {
        return { ...node, children: filteredChildren }
      }
      return null
    }

    data.forEach(node => {
      const filteredNode = filterNode(node)
      if (filteredNode) filtered.push(filteredNode)
    })

    return filtered
  }

  const handleSearch = value => {
    setSearchValue(value)
    const filtered = filterTreeData(treeData, value)
    setFilteredTreeData(filtered)
    if (value) {
      const getAllKeys = data => {
        let keys = []
        data.forEach(item => {
          keys.push(item.key)
          if (item.children) keys = keys.concat(getAllKeys(item.children))
        })
        return keys
      }
      setExpandedKeys(getAllKeys(filtered))
    }
  }

  const handleSelect = (keys, info) => {
    setSelectedKeys(keys)
    if (info.selected) {
      setSelectedNode(info.node)
      onChange?.(info.node)
    }
  }

  const handleExpand = keys => setExpandedKeys(keys)

  return (
    <>
      {/* Thông tin đơn vị */}
      <div
        style={{
          fontWeight: 600,
          marginBottom: "10px",
          fontSize: "15px",
          color: "#262626",
          display: "flex",
          alignItems: "center",
        }}
      >
        <HomeOutlined style={{ marginRight: "8px", color: "#1890ff" }} />
        Thông tin Đơn vị
      </div>

      {/* Search */}
      <Search
        placeholder="Tìm kiếm tên đơn vị..."
        allowClear
        prefix={<SearchOutlined style={{ color: "#bfbfbf" }} />}
        style={{
          width: "100%",
          borderRadius: "6px",
          marginBottom: "12px",
        }}
        value={searchValue}
        onChange={e => handleSearch(e.target.value)}
        size="middle"
      />

      {/* đơn vị bạn đã chọn */}
      <div
        style={{
          marginBottom: "14px",
          padding: "10px 12px",
          background: "#f6ffed",
          border: "1px solid #b7eb8f",
          borderRadius: "6px",
          fontSize: "14px",
          display: "flex",
          alignItems: "center",
          color: "#389e0d",
          minHeight: "40px",
        }}
      >
        {selectedNode ? (
          <>
            <TeamOutlined style={{ marginRight: "8px" }} />
            {selectedNode.title}
          </>
        ) : (
          <span style={{ color: "#8c8c8c" }}>Chưa chọn đơn vị nào</span>
        )}
      </div>

      {/* Danh sách đơn vị */}
      <div
        style={{
          fontWeight: 600,
          marginBottom: "10px",
          fontSize: "15px",
          color: "#262626",
          display: "flex",
          alignItems: "center",
        }}
      >
        Danh sách đơn vị
      </div>

      <div
        style={{
          flex: 1,
          height: "100%",
          overflow: "hidden",
          border: "1px solid #e8e8e8",
          borderRadius: "6px",
          backgroundColor: "#fafafa",
        }}
      >
        {loading ? (
          <div
            style={{
              textAlign: "center",
              padding: "40px",
              color: "#666",
            }}
          >
            <Spin size="default" />
            <div style={{ marginTop: "12px" }}>Đang tải dữ liệu...</div>
          </div>
        ) : filteredTreeData?.length > 0 ? (
          <Tree
            treeData={filteredTreeData}
            expandedKeys={expandedKeys}
            selectedKeys={selectedKeys}
            onExpand={handleExpand}
            onSelect={handleSelect}
            height={300}
            virtual
            showLine={{ showLeafIcon: false }}
            style={{
              fontSize: "14px",
              padding: "8px 12px",
              backgroundColor: "transparent",
              overflow: "auto",
            }}
            titleRender={node => (
              <span
                style={{
                  display: "inline-block",
                  padding: "4px 6px",
                  width: "100%",
                  borderRadius: "4px",
                  transition: "all 0.2s",
                  cursor: "pointer",
                }}
                onMouseEnter={e => {
                  e.currentTarget.style.backgroundColor = "#e6f7ff"
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.backgroundColor = "transparent"
                }}
              >
                {node.title}
              </span>
            )}
          />
        ) : (
          <Empty
            description="Không có dữ liệu đơn vị"
            image={Empty.PRESENTED_IMAGE_SIMPLE}
            style={{ marginTop: "40px" }}
          />
        )}
      </div>
    </>
  )
}

export default UnitSelect
