import { Form, theme } from "antd"
import { useEffect, useState } from "react"
import { useNavigate } from "react-router-dom"
import LayoutCommon from "src/components/Common/LayoutCommon"
import notice from "src/components/Notice"
import StepsCustom from "src/components/StepsCustom"
import SvgIcon from "src/components/SvgIcon"
import ROUTER from "src/router/ROUTER"
import GuestService from "src/services/GuestService"
import Step1 from "./components/Step1"
import Step2 from "./components/Step2"

import Step3 from "./components/Step3"
import Step4 from "./components/Step4"
import "./styles/BusinessRegistration.scss"

const BusinessRegistrationPage = () => {
  const [formStep1] = Form.useForm()
  const [formStep2] = Form.useForm()
  const [formStep3] = Form.useForm()
  const nav = useNavigate()

  const { token } = theme.useToken()
  const [current, setCurrent] = useState(0)
  const [formValues, setFormValues] = useState({})
  const [treeExternalData, setTreeExternalData] = useState({})
  const [loading, setLoading] = useState(false)
  const [isMobile, setIsMobile] = useState(false)

  useEffect(() => {
    const checkMobile = () => {
      setIsMobile(window.innerWidth <= 768)
    }

    checkMobile()
    window.addEventListener("resize", checkMobile)

    return () => window.removeEventListener("resize", checkMobile)
  }, [])

  const next = async () => {
    try {
      const valuesStep1 = await formStep1.validateFields()
      let valuesStep2 = {}
      let valuesStep3 = {}

      if (current === 1) valuesStep2 = await formStep2.validateFields()
      if (current === 2) valuesStep3 = await formStep3.validateFields()

      const values = { ...valuesStep1, ...valuesStep2, ...valuesStep3 }
      setCurrent(current + 1)

      setFormValues(values)
    } catch (error) {
      console.log("error", error)
    }
  }

  const prev = () => {
    setCurrent(current - 1)
  }

  const uploadFile = async imageBlob => {
    try {
      const formData = new FormData()
      formData.append("file", imageBlob)
      const res = await GuestService.uploadFile(formData)
      return res
    } finally {
      console.log("uploadFile")
    }
  }

  const success = async packageRegister => {
    if (loading) return
    setLoading(true)
    try {
      const valuesStep1 = await formStep1.validateFields()
      const valuesStep2 = await formStep2.validateFields()
      const valuesStep3 = await formStep3.validateFields()
      const values = { ...valuesStep1, ...valuesStep2, ...valuesStep3 }

      const uploadCCCD = await uploadFile(values?.CCCDImage[0]?.originFileObj)
      if (uploadCCCD?.isError) return
      const finalData = {
        ...values,
        CCCDImage: uploadCCCD?.Object,
        AccountID: values?.AccountID,
        DateIssue: formValues?.DateIssue?.format(),
      }
      console.log("finalData", finalData)
      const res = await GuestService.RegisterOrganization(finalData)
      console.log("submit", res)
      if (res?.isError) return
      notice({
        msg: "Đăng ký thành công. Vui lòng chờ xác thực từ quản trị viên.",
      })
      nav(ROUTER.HOME)
    } catch (error) {
      console.error("Lỗi khi đăng ký:", error)
    } finally {
      setLoading(false)
    }
  }

  const steps = [
    {
      title: (
        <div className="title-step">
          <div className="title-step__main no-wrap">
            <b>Thông tin </b>
          </div>
          <div className="title-step__sub ">
            Nhập thông tin doanh nghiệp của bạn
          </div>
        </div>
      ),
      icon: (
        <div className="icon-step">
          <SvgIcon name="csyt" />
        </div>
      ),
      tutorial:
        "Vui lòng bổ sung thông tin về người được ủy quyền sẽ đại diện cho công ty trong các vấn đề pháp lý.",
      content: <Step1 form={formStep1} next={next} />,
    },
    {
      title: (
        <div className="title-step">
          <div className="title-step__main no-wrap">
            <b>Chọn đơn vị</b>
          </div>
          <div className="title-step__sub ">Chọn đơn vị phù hợp</div>
        </div>
      ),
      icon: (
        <div className="icon-step">
          <SvgIcon name="building" />
        </div>
      ),
      content: (
        <Step2
          form={formStep2}
          next={next}
          prev={prev}
          treeExternalData={treeExternalData}
          setTreeExternalData={setTreeExternalData}
        />
      ),
    },
    {
      title: (
        <div className="title-step">
          <div className="title-step__main no-wrap">
            <b>Người đại diện</b>
          </div>
          <div className="title-step__sub ">Nhập thông tin người đại diện</div>
        </div>
      ),
      icon: (
        <div className="icon-step">
          <SvgIcon name="diem-danh" />
        </div>
      ),
      tutorial:
        "Vui lòng bổ sung thông tin về người được ủy quyền sẽ đại diện cho công ty trong các vấn đề pháp lý.",
      content: <Step3 form={formStep3} next={next} prev={prev} />,
    },
    {
      title: (
        <div className="title-step">
          <div className="title-step__main no-wrap">
            <b>Xác nhận lại</b>
          </div>
          <div className="title-step__sub ">
            Xác nhận lại các thông tin và nộp đơn
          </div>
        </div>
      ),
      icon: (
        <div className="icon-step">
          <SvgIcon name="check-special" />
        </div>
      ),
      tutorial:
        "Vui lòng xem xét kỹ lưỡng mọi thông tin trước khi nộp đơn đăng ký hội viên.",
      content: (
        <Step4
          success={success}
          prev={prev}
          formValues={formValues}
          treeExternalData={treeExternalData}
          setTreeExternalData={setTreeExternalData}
          setCurrent={setCurrent}
          loading={loading}
        />
      ),
    },
  ]

  const items = steps.map(item => ({
    key: item.title,
    title: item.title,
    icon: item.icon,
  }))

  const contentStyle = {}

  return (
    <div className="business-register">
      <LayoutCommon>
        <div className="business-register__title">
          <h1 className="business-register__title-main">
            Đăng Ký Hội Viên Cho Doanh Nghiệp
          </h1>
          <div className="business-register__title-sub">
            Hoàn tất đăng ký hội viên của bạn trong 4 bước đơn giản
          </div>
        </div>
        <div className="business-register__steps-box-menu">
          <div className="mb-16">
            <StepsCustom
              labelPlacement="vertical"
              current={current}
              items={items}
            />
          </div>
        </div>
        <div>
          {steps[current]?.tutorial && (
            <div
              style={{
                color: "#00000080",
                fontSize: isMobile ? "8px" : "12px",
                marginLeft: isMobile ? "5px" : "25px",
              }}
            >
              <span>{steps[current]?.tutorial}</span>
            </div>
          )}
        </div>
        <div className="business-register__steps-box">
          {steps?.map((item, idx) => (
            <div
              key={idx}
              style={{
                ...contentStyle,
                display: current === idx ? "block" : "none",
              }}
            >
              {item.content}
            </div>
          ))}
        </div>
      </LayoutCommon>
    </div>
  )
}

export default BusinessRegistrationPage
